#include <stdio.h>
int main() {
    int T, N, a, b;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int xor = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &a, &b);
            if (a > b) {
                int temp = a;
                a = b;
                b = temp;
            }
            xor ^= (b - a) / a;
        }
        if (xor == 0) {
            printf("NO\n");
        } else {
            printf("YES\n");
        }
    }
    return 0;
}

