        while (T-- > 0) {
            int N = sc.nextInt();
            int xor = 0;
            for (int i = 0; i < N; i++) {
                int a = sc.nextInt();
                int b = sc.nextInt();
                if (a > b) {
                    int temp = a;
                    a = b;
                    b = temp;
                }
                xor ^= (b - a) / a;
            }
            if (xor == 0) {
                System.out.println("NO");
            } else {
                System.out.println("YES");
            }
        }
    }
}

