const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    let xor = 0;
    for (let j = 0; j < N; j++) {
        const [a, b] = readline().split(' ').map(Number);
        if (a > b) {
            [a, b] = [b, a];
        }
        xor ^= Math.floor((b - a) / a);
    }
    if (xor === 0) {
        console.log('NO');
    } else {
        console.log('YES');
    }
}
